package main

import "fmt"

func main() {
    score := 100

    // Let's print the actual value
    fmt.Println("Value is:", score)

    // Let's print the ADDRESS of where it lives using &
    fmt.Println("Address is:", &score)
}

package main

import "fmt"

// Expects a POINTER to an int (written as *int)
func cheat(scoreAddress *int) {
    // Follow the address and forcefully change the data!
    *scoreAddress = 999 
}

func main() {
    score := 10

    // We pass the ADDRESS of score, not the number 10
    cheat(&score)

    fmt.Println("Final Score:", score)
}
